import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

# Build lookup: {(project_basename, package_id): version}
def pkg_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                m[(name, pkg['id'])] = pkg['resolvedVersion']
    return m

b = pkg_map(baseline)
a = pkg_map(after)

changes = []
unchanged = []
for key in sorted(set(b) | set(a)):
    proj, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv == av:
        unchanged.append((proj, pkg, bv))
    else:
        changes.append((proj, pkg, bv, av))

if changes:
    print('CHANGES:')
    for c in changes: print(f'  {c}')
else:
    print('NO CHANGES - fully version-neutral')

print()
print('UNCHANGED:')
for u in unchanged:
    print(f'  {u[0]} | {u[1]} | {u[2]}')
"

